]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Data‑calculation model for Coulomb‑Viscous friction identification."
    DTDFVocab:inputTo DataProcessingEngine
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Data‑calculation model for Stribeck friction identification."
    DTDFVocab:inputTo DataProcessingEngine
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Data‑calculation model for Dahl friction identification."
    DTDFVocab:inputTo DataProcessingEngine
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "Data‑calculation model for LuGre friction identification."
    DTDFVocab:inputTo DataProcessingEngine
]

// C5: Data instances
instance MeasuredMotorCurrentData : DTDFVocab:Data [
    base:desc "Measured motor current supplied by MotorCurrentSensor."
