]

instance MeasuredMotorTorqueData : DTDFVocab:Data [
    base:desc "Measured motor torque derived from current measurement and motor model."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance MeasuredMotorAngularVelocityData : DTDFVocab:Data [
    base:desc "Measured angular velocity derived from motor encoder position."
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance MeasuredGearboxAngularVelocityData : DTDFVocab:Data [
    base:desc "Measured gearbox angular velocity derived from gearwheel encoder position."
    DTDFVocab:fromData GearboxPositionDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance SimulatedMotorCurrentData : DTDFVocab:Data [
    base:desc "Simulated motor current generated by the SimulinkMotorGearboxModel."
