    DTDFVocab:inputTo SimulationEngine
]

instance SimulatedMotorTorqueData : DTDFVocab:Data [
    base:desc "Simulated motor torque from the Simulink model."
    DTDFVocab:fromData SimulatedMotorTorqueDataTransmitted
    DTDFVocab:inputTo SimulationEngine
]

instance SimulatedMotorAngularVelocityData : DTDFVocab:Data [
    base:desc "Simulated motor angular velocity from the Simulink model."
    DTDFVocab:fromData SimulatedMotorAngularVelocityDataTransmitted
    DTDFVocab:inputTo SimulationEngine
]

instance SimulatedGearboxAngularVelocityData : DTDFVocab:Data [
    base:desc "Simulated gearbox angular velocity from the Simulink model."
    DTDFVocab:fromData SimulatedGearboxAngularVelocityDataTransmitted
    DTDFVocab:inputTo SimulationEngine
]

